package http

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/http"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type HTTPProxy struct {
	http.UnimplementedHTTPServer
	client http.HTTPClient
}

func init() {
	proxyutil.Register(&http.HTTP_ServiceDesc, NewHTTPProxy)
}
func NewHTTPProxy(cc grpc.ClientConnInterface) http.HTTPServer {
	return &HTTPProxy{client: http.NewHTTPClient(cc)}
}
func (p *HTTPProxy) Fetch(ctx context.Context, in *http.FetchRequest) (*http.FetchResponse, error) {
	return proxyutil.ProxyMethod[http.FetchRequest, http.FetchResponse](p.client.Fetch)(ctx, in)
}
